import logging
import json
import os
from azure.functions import TimerRequest
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.credentials import AzureSasCredential
from azure.identity import DefaultAzureCredential

def main(mytimer: TimerRequest):
    try:
        # Initialize credentials using managed identity
        credential = DefaultAzureCredential()
        
        # Blob Storage connection
        blob_service_client = BlobServiceClient(
            account_url=os.environ['STORAGE_ACCOUNT_URL'],
            credential=credential
        )
        
        # Cosmos DB connection
        cosmos_client = CosmosClient(
            endpoint=os.environ['COSMOS_DB_ENDPOINT'],
            credential=credential
        )
        
        # Event Grid connection
        event_grid_client = EventGridPublisherClient(
            endpoint=os.environ['EVENT_GRID_ENDPOINT'],
            credential=credential
        )
        
        # Process blobs
        container_client = blob_service_client.get_container_client(os.environ['BLOB_CONTAINER_NAME'])
        blob_list = container_client.list_blobs()
        
        for blob in blob_list:
            # Read blob content
            blob_data = container_client.get_blob_client(blob).download_blob().readall()
            
            # Process data (example: count words)
            processed_data = {
                'filename': blob.name,
                'word_count': len(blob_data.decode('utf-8').split()),
                'processed_at': '2023-01-01T00:00:00Z'
            }
            
            # Write to Cosmos DB
            database = cosmos_client.get_database_client(os.environ['COSMOS_DB_NAME'])
            container = database.get_container_client(os.environ['COSMOS_CONTAINER_NAME'])
            container.create_item(body=processed_data)
            
            # Send notification via Event Grid
            event_grid_client.send([
                {
                    'topic': '/subscriptions/subscription-id/resourceGroups/resource-group-name/providers/Microsoft.Storage/storageAccounts/storage-account-name',
                    'subject': f'/blobServices/default/containers/{os.environ["BLOB_CONTAINER_NAME"]}/blobs/{blob.name}',
                    'eventType': 'BlobCreated',
                    'eventTime': '2023-01-01T00:00:00Z',
                    'data': {
                        'url': f"https://{os.environ['STORAGE_ACCOUNT_NAME']}.blob.core.windows.net/{os.environ['BLOB_CONTAINER_NAME']}/{blob.name}",
                        'processed_data': processed_data
                    }
                }
            ])
            
            logging.info(f"Processed blob: {blob.name}")
            
    except Exception as e:
        logging.error(f"Error processing blobs: {str(e)}")
        raise